css:
body {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 11px;
    color: #000;
}

.company-header {
    margin-bottom: 5px;
}

.company-name {
    font-size: 16px;
    font-weight: bold;
    text-transform: uppercase;
    text-align: left;
    margin-bottom: 5px;
}

.company-address {
    margin-top: 5px;
    line-height: 1.5;
}

.party-section {
    width: 100%;
    margin-top: 5px;
    margin-bottom: 5px;
}

.party-left {
    float: left;
    width: 70%;
}

.party-right {
    float: right;
    width: 25%;
    text-align: right;
}

.clearfix {
    clear: both;
}

.separator {
    border-top: 1px solid #000;
    margin: 5px 0;
}
.details-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0px !important;
    margin-bottom: 0px !important;
}

.details-table td {
    padding: 0px !important;
    line-height: 1.1 !important;
    vertical-align: top;
    border: none !important;
}

.details-table tr {
    height: 16px !important;
}

.label {
    width: 170px;
    font-weight: bold;
    white-space: nowrap;
}

.value {
    padding-left: 0;
}

.label {
    width: 180px;
    font-weight: bold;
    white-space: nowrap;
    border: none !important;
    padding-right: 10px;
}

.section-title {
    font-weight: bold;
    text-decoration: underline;
    margin-top: 0px !important;
    margin-bottom: 2px !important;
    padding: 0px !important;
}

.adjustment-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
    margin-top: 10px;
    font-size: 13px;
}

.adjustment-table th,
.adjustment-table td {
    border: 1px solid #000 !important;
    padding: 1px 3px !important;
    line-height: 1.0 !important;
}

.adjustment-table tr {
    border: 1px solid #000 !important;
}

.adjustment-table tbody tr {
    border-bottom: 1px solid #000 !important;
}

.adjustment-table th {
    text-align: center;
    font-weight: bold;
    background: #f5f5f5;
}

.adjustment-table td {
    vertical-align: middle;
}
.company-header,
.party-section,
.details-table,
.section-title {
    font-size: 13px;
}
.adjustment-table table,
.adjustment-table tr,
.adjustment-table td,
.adjustment-table th {
    border-collapse: collapse !important;
}
.print-format {
    padding: 0 !important;
    margin: 0 !important;
}

p {
    margin: 0;
}

table {
    margin-bottom: 0;
}
.details-table + .section-title {
    margin-top: 0px !important;
}

.print-format p,
.print-format div,
.print-format table {
    margin-bottom: 0px !important;
}
.adjustment-table {
    border-collapse: collapse !important;
    border-spacing: 0 !important;
}

.adjustment-table tr {
    height: 18px !important;
}

.adjustment-table td {
    margin: 0 !important;
}

.adjustment-table th {
    margin: 0 !important;
}
